export const checkId = 'dynamic-port';
export const name = 'Dynamic Port Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const NONPROD_RE = /^(?:examples?|demos?|test|tests|spec|__tests__|fixtures?|playground|benchmark|docs|\.github|coverage|storybook|stories|\.storybook|e2e|cypress|playwright|mock|mocks|vendor)\//;
const TEST_FILE_RE = /\.(?:test|spec|d)\.(?:js|ts|jsx|tsx|mjs|cjs)$/;
const JS_RE = /\.(?:js|ts|jsx|tsx|mjs|cjs)$/;

function classifyPath(p) {
  if (NONPROD_RE.test(p)) return 'nonprod';
  if (TEST_FILE_RE.test(p)) return 'nonprod';
  if (/(?:^|\/)node_modules\//.test(p)) return 'nonprod';
  if (/(?:^|\/)dist\//.test(p)) return 'nonprod';
  if (/(?:^|\/)build\//.test(p)) return 'nonprod';
  return 'prod';
}

function isFile(p) {
  return !p.endsWith('/');
}

function hasServerSignals(packageJson, tree) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  const scripts = packageJson.scripts || {};

  const serverDepRe = /^(?:express|fastify|koa|hono|polka|restify|connect|micro|sirv|serve-static|http-server|next|nuxt|astro|nitro|h3|remix|solid-start)$/;
  const hasServerDep = Object.keys(deps).some(d => serverDepRe.test(d));
  const hasServerScript = Object.entries(scripts).some(([k, v]) => {
    if (!v) return false;
    return /^(start|serve|dev|preview)$/.test(k) && /node|ts-node|nodemon|pm2|next|nuxt|astro|solid-start|remix|serve|listen|http-server/.test(v);
  });
  const hasDeployArtifact = tree.some(p => isFile(p) && /^(?:Dockerfile|Procfile|fly\.toml|vercel\.json|netlify\.toml|render\.yaml|app\.yaml|wrangler\.toml|docker-compose\.yml|docker-compose\.yaml)$/.test(p));
  const hasRootServerFile = tree.some(p => isFile(p) && /^(?:server|app|index|main|start|listen)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p));

  return hasServerDep || hasServerScript || hasDeployArtifact || hasRootServerFile;
}

function isLikelyLibrary(packageJson, tree) {
  if (!packageJson) return false;
  const scripts = packageJson.scripts || {};

  if (scripts.start && /node|ts-node|nodemon|pm2|next|nuxt|astro|serve|listen/.test(scripts.start)) return false;
  if (scripts.serve) return false;
  if (scripts.preview && /next|nuxt|astro|vite/.test(scripts.preview)) return false;

  if (tree.some(p => isFile(p) && /^(?:Dockerfile|fly\.toml|vercel\.json|netlify\.toml|render\.yaml|app\.yaml|wrangler\.toml)$/.test(p))) return false;
  if (tree.some(p => isFile(p) && /^(?:next\.config|nuxt\.config|astro\.config|remix\.config|svelte\.config|solid\.config|vite\.config|nitro\.config)/.test(p))) return false;

  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  const serverDepRe = /^(?:express|fastify|koa|hono|polka|restify|connect|micro|sirv|serve-static|http-server|next|nuxt|astro|nitro|h3|remix|solid-start)$/;
  if (Object.keys(deps).some(d => serverDepRe.test(d))) return false;

  if (packageJson.bin && !scripts.start) return true;

  const keywords = packageJson.keywords || [];
  const libKeywords = ['library', 'lib', 'plugin', 'tool', 'cli', 'utility', 'utils', 'helper', 'client', 'sdk', 'middleware', 'webpack', 'build', 'bundler', 'compiler'];
  const hasLibKw = keywords.some(k => libKeywords.includes(k.toLowerCase()));

  if (packageJson.peerDependencies && hasLibKw) return true;

  if ((packageJson.main || packageJson.module || packageJson.exports) && !scripts.start && !scripts.dev) {
    if (packageJson.workspaces && tree.some(p => p.startsWith('packages/')) && !tree.some(p => p.startsWith('apps/'))) {
      return true;
    }
    if (hasLibKw) return true;
  }

  return false;
}

function selectFiles(tree, packageJson) {
  const candidates = [];

  const add = (p, prio) => {
    if (!isFile(p) || !tree.includes(p)) return;
    candidates.push({ path: p, priority: prio });
  };

  ['package.json', 'Dockerfile', 'Procfile', 'fly.toml', 'vercel.json', 'netlify.toml', 'render.yaml', 'app.yaml', 'wrangler.toml', 'docker-compose.yml', 'docker-compose.yaml']
    .forEach(f => add(f, 0));

  tree.filter(p => isFile(p) && /^(?:server|app|index|main|start|listen|www|bin|cli|run|application|entry|bootstrap|gateway|listener|serve)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !p.includes('/'))
    .forEach(p => add(p, 1));

  tree.filter(p => isFile(p) && /^(?:src|lib)\/(?:server|app|index|main|start|listen|run|application|entry|bootstrap|gateway|listener|serve)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p))
    .forEach(p => add(p, 2));

  tree.filter(p => isFile(p) && /^apps\/[^/]+\/(?:src\/)?(?:server|app|index|main|start|listen)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p))
    .forEach(p => add(p, 3));

  tree.filter(p => isFile(p) && /^packages\/[^/]+\/(?:src\/)?(?:server|app|index|main|start|listen)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p))
    .forEach(p => add(p, 4));

  tree.filter(p => isFile(p) && /^(?:next\.config|nuxt\.config|astro\.config|remix\.config|svelte\.config|vite\.config|solid\.config|nitro\.config)/.test(p))
    .forEach(p => add(p, 5));

  if (candidates.length < 10) {
    tree.filter(p => {
      if (!isFile(p)) return false;
      if (!JS_RE.test(p)) return false;
      if (TEST_FILE_RE.test(p)) return false;
      if (/(?:^|\/)node_modules\//.test(p)) return false;
      if (/(?:^|\/)dist\//.test(p)) return false;
      if (/(?:^|\/)build\//.test(p)) return false;
      return /(?:listen|port|server)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p);
    }).slice(0, 8).forEach(p => add(p, 6));
  }

  if (candidates.length < 8) {
    tree.filter(p => {
      if (!isFile(p)) return false;
      if (!JS_RE.test(p)) return false;
      if (TEST_FILE_RE.test(p)) return false;
      if (/(?:^|\/)node_modules\//.test(p)) return false;
      if (/(?:^|\/)dist\//.test(p)) return false;
      if (/(?:^|\/)build\//.test(p)) return false;
      return /(?:^|\/)packages\/[^/]+\/(?:src\/|lib\/)?(?:[^/]*(?:server|app|index|main|listen|port)[^/]*)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p) ||
             /(?:^|\/)apps\/[^/]+\/(?:src\/|lib\/)?(?:[^/]*(?:server|app|index|main|listen|port)[^/]*)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p) ||
             /(?:^|\/)src\/(?:[^/]*(?:server|app|index|main|listen|port)[^/]*)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p) ||
             /(?:^|\/)lib\/(?:[^/]*(?:server|app|index|main|listen|port)[^/]*)\.(?:js|ts|jsx|tsx|mjs|cjs)$/.test(p);
    }).slice(0, 10).forEach(p => add(p, 7));
  }

  if (candidates.length < 5) {
    tree.filter(p => isFile(p) && /^[^/]+\.(?:js|ts|mjs|cjs)$/.test(p) && !TEST_FILE_RE.test(p))
      .slice(0, 5).forEach(p => add(p, 8));
  }

  candidates.sort((a, b) => a.priority - b.priority);
  const seen = new Set();
  const result = [];
  for (const c of candidates) {
    if (!seen.has(c.path)) {
      seen.add(c.path);
      result.push(c.path);
    }
  }
  return result.slice(0, 15);
}

const DYNAMIC_PATTERNS = [
  /process\.env\.PORT\b/,
  /process\.env\['PORT'\]/,
  /process\.env\["PORT"\]/,
  /Deno\.env\.get\(['"]PORT['"]\)/,
  /Bun\.env\.PORT\b/,
  /import\.meta\.env\.PORT\b/,
  /Number\s*\(\s*process\.env\.PORT\s*\)/,
  /parseInt\s*\(\s*process\.env\.PORT\s*\)/,
  /\+\s*process\.env\.PORT\b/,
  /process\.env\.PORT\s*(?:\|\||\?\?)/,
  /PORT\s*=\s*process\.env\.PORT/,
  /\{\s*PORT\s*=\s*\d+\s*\}\s*=\s*process\.env/,
  /listen\s*\(\s*(?:process\.env\.PORT|Deno\.env\.get\(['"]PORT['"]\)|Bun\.env\.PORT|import\.meta\.env\.PORT)/,
  /port\s*:\s*process\.env\.PORT\b/,
  /port\s*:\s*Number\s*\(\s*process\.env\.PORT\s*\)/,
  /port\s*:\s*parseInt\s*\(\s*process\.env\.PORT\s*\)/,
];

const HARDCODED_PATTERNS = [
  /\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /port\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /PORT\s*=\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /const\s+PORT\s*=\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /let\s+PORT\s*=\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /var\s+PORT\s*=\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
];

function scanScripts(pkg) {
  const findings = [];
  if (!pkg?.scripts) return findings;
  for (const [name, script] of Object.entries(pkg.scripts)) {
    if (!script || typeof script !== 'string') continue;
    if (/process\.env\.PORT|\$PORT\b/.test(script)) {
      findings.push({ file: 'package.json', issue: `Script "${name}" references dynamic PORT` });
    }
    const m = script.match(/\b(?:PORT|port)\s*[=:]\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/);
    if (m) {
      findings.push({ file: 'package.json', issue: `Script "${name}" hardcodes port ${m[1]}` });
    }
  }
  return findings;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no server port needed', findings: [] };
    }

    if (repoType === 'library' || isLikelyLibrary(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library/tool detected — no server port configuration needed', findings: [] };
    }

    const filesToScan = selectFiles(tree, packageJson);
    const allFindings = [];

    for (const filePath of filesToScan) {
      try {
        const content = await files.get(filePath);
        if (!content) continue;

        const location = classifyPath(filePath);

        if (filePath === 'Dockerfile') {
          const lines = content.split('\n');
          for (let i = 0; i < lines.length; i++) {
            if (/\bEXPOSE\s+\$PORT\b/.test(lines[i])) {
              allFindings.push({ file: filePath, line: i + 1, issue: 'Dockerfile exposes dynamic $PORT', location });
            }
          }
          continue;
        }

        if (filePath === 'Procfile') {
          if (/\$PORT/.test(content)) {
            allFindings.push({ file: filePath, issue: 'Procfile references $PORT', location });
          }
          continue;
        }

        if (filePath.endsWith('package.json')) {
          try {
            const subPkg = JSON.parse(content);
            const scriptFindings = scanScripts(subPkg);
            scriptFindings.forEach(f => { f.file = filePath; f.location = location; });
            allFindings.push(...scriptFindings);
          } catch {
            // ignore JSON parse errors for sub-packages
          }
          continue;
        }

        const lines = content.split('\n');
        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];
          const trimmed = line.trimStart();
          if (trimmed.startsWith('//') || trimmed.startsWith('/*') || trimmed.startsWith('*')) continue;

          for (const pat of DYNAMIC_PATTERNS) {
            if (pat.test(line)) {
              allFindings.push({ file: filePath, line: i + 1, issue: 'Dynamic port configuration (process.env.PORT or equivalent)', location });
              break;
            }
          }

          for (const pat of HARDCODED_PATTERNS) {
            const m = line.match(pat);
            if (m) {
              const port = m[1] || m[2] || 'hardcoded';
              allFindings.push({ file: filePath, line: i + 1, issue: `Hardcoded port (${port})`, location });
              break;
            }
          }
        }
      } catch (err) {
        console.error(`Error reading ${filePath}:`, err);
      }
    }

    const rootScriptFindings = scanScripts(packageJson);
    rootScriptFindings.forEach(f => { f.location = 'prod'; });
    allFindings.push(...rootScriptFindings);

    const prodFindings = allFindings.filter(f => f.location === 'prod');
    const nonprodFindings = allFindings.filter(f => f.location === 'nonprod');

    const prodDynamic = prodFindings.some(f => f.issue.includes('Dynamic port'));
    const prodHardcoded = prodFindings.some(f => f.issue.includes('Hardcoded port'));

    if (prodDynamic && !prodHardcoded) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found (process.env.PORT)', findings: allFindings };
    }

    if (prodHardcoded && !prodDynamic) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded port detected — should use process.env.PORT', findings: allFindings };
    }

    if (prodDynamic && prodHardcoded) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Both dynamic and hardcoded port patterns found in production files', findings: allFindings };
    }

    const depNames = packageJson ? Object.keys({ ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) }) : [];
    const frameworkDepRe = /^(?:express|fastify|koa|hono|polka|restify|connect|micro|sirv|serve-static|http-server|next|nuxt|astro|nitro|h3|remix|solid-start)$/;
    const hasFrameworkDep = depNames.some(d => frameworkDepRe.test(d));
    const hasFrameworkConfig = tree.some(p => isFile(p) && /^(?:next\.config|nuxt\.config|astro\.config|remix\.config|svelte\.config|solid\.config|vite\.config|nitro\.config)/.test(p));

    if (hasFrameworkDep || hasFrameworkConfig) {
      return { checkId, status: 'pass', confidence: 'medium', message: 'Framework supports dynamic port configuration', findings: allFindings };
    }

    const hasExplicitServerFiles = filesToScan.some(f => /(?:server|listen|port|Dockerfile|Procfile|docker-compose|app\.)/i.test(f));
    const serverSignals = hasServerSignals(packageJson, tree);

    if (repoType === 'framework' && hasExplicitServerFiles) {
      return { checkId, status: 'pass', confidence: 'medium', message: 'Framework repo — server port handled by framework core', findings: allFindings };
    }

    if (!serverSignals && !hasExplicitServerFiles) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No server runtime detected — port check not applicable', findings: allFindings };
    }

    if (nonprodFindings.length > 0) {
      return { checkId, status: 'check-it', confidence: 'low', message: 'No production port patterns found; patterns only in examples/tests', findings: allFindings };
    }

    return { checkId, status: 'not-applicable', confidence: 'low', message: 'No port configuration patterns detected in scanned files', findings: allFindings };

  } catch (err) {
    console.error('dynamic-port check fatal error:', err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [{ file: 'internal', issue: `Fatal error: ${err.message}` }] };
  }
}
